const binaryData = $input.item.binary;

// Получаем все binary ключи (data0, data1, data2, ...)
const binaryKeys = Object.keys(binaryData);

// Массив для base64 изображений
const images = [];

// Читаем все binary файлы
for (const key of binaryKeys) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, key);
  const base64 = buffer.toString('base64');
  const mimeType = binaryData[key]?.mimeType || 'image/jpeg';

  images.push({
    base64: base64,
    mimeType: mimeType
  });
}

// Возвращаем
return {
  json: {
    images: images,
    imageCount: images.length
  }
};

const images = $input.item.json.images;
const caption = $('Telegram Trigger').item.json.message.caption;

// Проверка на пустой промпт
if (!caption || caption.trim() === '') {
  throw new Error('❌ Ошибка: Не указан промпт! Добавьте описание к архиву.');
}

// Формируем parts массив
const parts = [
  {
    text: caption
  }
];

// Добавляем все изображения из массива
for (const img of images) {
  parts.push({
    inlineData: {
      mimeType: img.mimeType,
      data: img.base64
    }
  });
}

// Собираем финальный JSON для Gemini
const requestBody = {
  contents: [
    {
      parts: parts
    }
  ],
  generationConfig: {
    responseModalities: ["TEXT", "IMAGE"],
    thinkingConfig: {
      includeThoughts: true
    }
  }
};

return {
  json: requestBody
};

let combinedPrompt = '';

// Вариант 1: Пытаемся взять из Prompt2 (HTTP ответ от Gemini)
try {
  const response = $('Prompt2').first().json;
  const parts = response.candidates[0].content.parts;

  const texts = [];
  for (const part of parts) {
    if (part.text) {
      // Убираем лишние переносы в конце и начале
      texts.push(part.text.trim());
    }
  }

  if (texts.length > 0) {
    combinedPrompt = texts.join('\n\n---\n\n');
  }
} catch (e) {
  // Prompt2 не выполнен, идем дальше
}

// Вариант 2: Если Prompt2 пустой, берем из Merge1
if (!combinedPrompt) {
  try {
    combinedPrompt = $('Merge1').first().json["post prompt"] || '';
  } catch (e) {
    // Merge1 не выполнен, идем дальше
  }
}

// Вариант 3: Если Merge1 пустой, берем из Merge
if (!combinedPrompt) {
  try {
    combinedPrompt = $('Merge').first().json["post prompt"] || '';
  } catch (e) {
    // Merge не выполнен
  }
}

// Fallback на пустую строку
if (!combinedPrompt) {
  combinedPrompt = 'No prompt available';
}

return {
  json: {
    "post prompt": combinedPrompt
  }
};

